sourcesContent:
import { useState, useEffect } from "react";

const NAV_LINKS = ["Ana Sayfa", "Hakkımızda", "Menü", "Şubeler", "İletişim"];

const MENU_ITEMS = [
  { category: "Espresso Bazlı", items: [
    { name: "Espresso", desc: "Yoğun ve aromatik tek shot", price: "45" },
    { name: "Americano", desc: "Espresso ve sıcak su", price: "55" },
    { name: "Cappuccino", desc: "Espresso, buharlanmış süt ve köpük", price: "65" },
    { name: "Latte", desc: "Kremalı ve yumuşak espresso", price: "70" },
    { name: "Flat White", desc: "Velvet süt ile güçlü espresso", price: "75" },
    { name: "Cortado", desc: "Espresso ve eşit süt", price: "60" },
  ]},
  { category: "Soğuk İçecekler", items: [
    { name: "Cold Brew", desc: "12 saat soğuk demleme", price: "75" },
    { name: "Iced Latte", desc: "Buz üzerinde kremalı latte", price: "70" },
    { name: "Frappe", desc: "Blended coffee delight", price: "80" },
    { name: "Nitro Cold Brew", desc: "Azot gazlı velvet kahve", price: "90" },
  ]},
  { category: "Özel Lezzetler", items: [
    { name: "Caramel Macchiato", desc: "Karamel sos ile katmanlı lezzet", price: "80" },
    { name: "Mocha", desc: "Çikolata ve espresso", price: "75" },
    { name: "Hazelnut Latte", desc: "Fındık aromalı latte", price: "75" },
    { name: "Vanilla Latte", desc: "Vanilyalı kremalı latte", price: "75" },
  ]},
];

const BRANCHES = [
  { name: "Kadıköy Şube", address: "Moda Cad. No:42, Kadıköy, İstanbul", phone: "+90 216 000 00 01", hours: "07:00 - 22:00", mapUrl: "https://maps.google.com/?q=Kadikoy,Istanbul" },
  { name: "Beşiktaş Şube", address: "Çarşı Sok. No:15, Beşiktaş, İstanbul", phone: "+90 212 000 00 02", hours: "07:00 - 23:00", mapUrl: "https://maps.google.com/?q=Besiktas,Istanbul" },
  { name: "Nişantaşı Şube", address: "Abdi İpekçi Cad. No:8, Nişantaşı, İstanbul", phone: "+90 212 000 00 03", hours: "08:00 - 22:00", mapUrl: "https://maps.google.com/?q=Nisantasi,Istanbul" },
  { name: "Levent Şube", address: "Büyükdere Cad. No:201, Levent, İstanbul", phone: "+90 212 000 00 04", hours: "07:00 - 21:00", mapUrl: "https://maps.google.com/?q=Levent,Istanbul" },
];

const WHATSAPP_NUMBER = "905001234567";

export default function App() {
  const [menuCat, setMenuCat] = useState(0);
  const [menuOpen, setMenuOpen] = useState(false);
  const [heroVisible, setHeroVisible] = useState(false);

  useEffect(() => {
    setTimeout(() => setHeroVisible(true), 100);
  }, []);

  const scrollTo = (id) => {
    setMenuOpen(false);
    document.getElementById(id)?.scrollIntoView({ behavior: "smooth" });
  };

  const sectionIds = ["home", "about", "menu", "branches", "contact"];

  return (
    <div style={{ fontFamily: "'Cormorant Garamond', 'Georgia', serif", background: "#f8f6f1", color: "#0a1628", minHeight: "100vh" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;0,700;1,300;1,400&family=Jost:wght@300;400;500;600&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        :root {
          --navy: #0a1628;
          --navy-light: #162140;
          --navy-mid: #1e3a5f;
          --gold: #c9a84c;
          --cream: #f8f6f1;
          --white: #ffffff;
        }
        html { scroll-behavior: smooth; }
        body { overflow-x: hidden; }
        .jost { font-family: 'Jost', sans-serif; }
        .nav-link {
          font-family: 'Jost', sans-serif;
          font-size: 13px;
          letter-spacing: 2px;
          text-transform: uppercase;
          color: rgba(255,255,255,0.8);
          cursor: pointer;
          transition: color 0.3s;
          background: none; border: none;
          padding: 4px 0;
          position: relative;
        }
        .nav-link::after {
          content: '';
          position: absolute;
          bottom: 0; left: 0;
          width: 0; height: 1px;
          background: var(--gold);
          transition: width 0.3s;
        }
        .nav-link:hover { color: var(--gold); }
        .nav-link:hover::after { width: 100%; }
        .hero-text {
          opacity: 0;
          transform: translateY(30px);
          transition: opacity 0.9s ease, transform 0.9s ease;
        }
        .hero-text.visible { opacity: 1; transform: translateY(0); }
        .hero-delay-1 { transition-delay: 0.2s; }
        .hero-delay-2 { transition-delay: 0.5s; }
        .hero-delay-3 { transition-delay: 0.8s; }
        .btn-primary {
          background: var(--gold);
          color: var(--navy);
          font-family: 'Jost', sans-serif;
          font-size: 12px;
          letter-spacing: 2.5px;
          text-transform: uppercase;
          font-weight: 600;
          padding: 16px 40px;
          border: none;
          cursor: pointer;
          transition: all 0.3s;
          display: inline-block;
        }
        .btn-primary:hover { background: #e0b855; transform: translateY(-2px); box-shadow: 0 8px 24px rgba(201,168,76,0.35); }
        .btn-outline {
          background: transparent;
          color: var(--white);
          font-family: 'Jost', sans-serif;
          font-size: 12px;
          letter-spacing: 2.5px;
          text-transform: uppercase;
          font-weight: 500;
          padding: 15px 40px;
          border: 1px solid rgba(255,255,255,0.5);
          cursor: pointer;
          transition: all 0.3s;
        }
        .btn-outline:hover { border-color: var(--gold); color: var(--gold); }
        .section-label {
          font-family: 'Jost', sans-serif;
          font-size: 11px;
          letter-spacing: 4px;
          text-transform: uppercase;
          color: var(--gold);
          margin-bottom: 16px;
        }
        .card-hover { transition: transform 0.3s, box-shadow 0.3s; }
        .card-hover:hover { transform: translateY(-6px); box-shadow: 0 20px 50px rgba(10,22,40,0.15); }
        .menu-cat-btn {
          font-family: 'Jost', sans-serif;
          font-size: 12px;
          letter-spacing: 2px;
          text-transform: uppercase;
          background: none;
          border: 1px solid rgba(10,22,40,0.2);
          padding: 10px 24px;
          cursor: pointer;
          transition: all 0.3s;
          color: var(--navy);
        }
        .menu-cat-btn.active, .menu-cat-btn:hover {
          background: var(--navy);
          color: var(--white);
          border-color: var(--navy);
        }
        .menu-cat-btn.active-gold {
          background: var(--gold) !important;
          color: var(--navy) !important;
          border-color: var(--gold) !important;
        }
        .branch-card {
          background: white;
          border: 1px solid rgba(10,22,40,0.08);
          padding: 36px;
          transition: all 0.3s;
        }
        .branch-card:hover {
          border-color: var(--navy-mid);
          box-shadow: 0 16px 48px rgba(10,22,40,0.12);
          transform: translateY(-4px);
        }
        .wa-btn {
          position: fixed;
          bottom: 32px; right: 32px;
          background: #25D366;
          color: white;
          width: 60px; height: 60px;
          border-radius: 50%;
          display: flex; align-items: center; justify-content: center;
          cursor: pointer;
          box-shadow: 0 8px 24px rgba(37,211,102,0.4);
          z-index: 1000;
          border: none;
          transition: all 0.3s;
          text-decoration: none;
        }
        .wa-btn:hover { transform: scale(1.1); box-shadow: 0 12px 32px rgba(37,211,102,0.5); }
        .divider { width: 60px; height: 2px; background: var(--gold); }
        .input-field {
          width: 100%;
          background: transparent;
          border: none;
          border-bottom: 1px solid rgba(255,255,255,0.3);
          padding: 12px 0;
          color: white;
          font-family: 'Jost', sans-serif;
          font-size: 14px;
          outline: none;
          transition: border-color 0.3s;
        }
        .input-field::placeholder { color: rgba(255,255,255,0.4); }
        .input-field:focus { border-bottom-color: var(--gold); }
        .floating-circle {
          position: absolute;
          border-radius: 50%;
          background: rgba(201,168,76,0.05);
          animation: float 8s ease-in-out infinite;
        }
        @keyframes float {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-20px); }
        }
        .grain-overlay {
          position: absolute; inset: 0;
          pointer-events: none;
          opacity: 0.04;
          background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");
        }
        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .mobile-toggle { display: block !important; }
          .two-col { grid-template-columns: 1fr !important; }
          .hero-title { font-size: 48px !important; }
        }
        .mobile-toggle { display: none; }
        .social-link {
          color: rgba(255,255,255,0.4);
          font-family: 'Jost', sans-serif;
          font-size: 12px;
          letter-spacing: 1px;
          text-decoration: none;
          transition: color 0.3s;
        }
        .social-link:hover { color: var(--gold); }
      `}</style>

      {/* NAVBAR */}
      <nav style={{
        position: "fixed", top: 0, left: 0, right: 0, zIndex: 900,
        background: "rgba(10,22,40,0.96)", backdropFilter: "blur(16px)",
        borderBottom: "1px solid rgba(255,255,255,0.06)",
        padding: "0 40px", height: "72px",
        display: "flex", alignItems: "center", justifyContent: "space-between"
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: "12px", cursor: "pointer" }} onClick={() => scrollTo("home")}>
          <div style={{ width: "36px", height: "36px", background: "var(--gold)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "18px" }}>☕</div>
          <div>
            <div style={{ color: "white", fontWeight: 700, fontSize: "18px", letterSpacing: "1px", lineHeight: 1 }}>COFFEE</div>
            <div className="jost" style={{ color: "var(--gold)", fontSize: "10px", letterSpacing: "4px", lineHeight: 1 }}>EXPRESS</div>
          </div>
        </div>

        <div className="desktop-nav" style={{ display: "flex", gap: "36px" }}>
          {NAV_LINKS.map((l, i) => (
            <button key={l} className="nav-link" onClick={() => scrollTo(sectionIds[i])}>{l}</button>
          ))}
        </div>

        <a href={`https://wa.me/${WHATSAPP_NUMBER}`} target="_blank" rel="noopener noreferrer"
          className="desktop-nav btn-primary jost"
          style={{ display: "flex", fontSize: "11px", padding: "10px 20px", textDecoration: "none", alignItems: "center", gap: "8px" }}>
          💬 WhatsApp
        </a>

        <button className="mobile-toggle" onClick={() => setMenuOpen(!menuOpen)}
          style={{ background: "none", border: "none", color: "white", fontSize: "24px", cursor: "pointer" }}>
          {menuOpen ? "✕" : "☰"}
        </button>
      </nav>

      {menuOpen && (
        <div style={{ position: "fixed", top: "72px", left: 0, right: 0, zIndex: 899, background: "var(--navy)", padding: "24px 40px", display: "flex", flexDirection: "column", gap: "20px" }}>
          {NAV_LINKS.map((l, i) => (
            <button key={l} className="nav-link" style={{ textAlign: "left" }} onClick={() => scrollTo(sectionIds[i])}>{l}</button>
          ))}
        </div>
      )}

      {/* HERO */}
      <section id="home" style={{ minHeight: "100vh", background: "var(--navy)", position: "relative", overflow: "hidden", display: "flex", alignItems: "center", paddingTop: "72px" }}>
        <div className="grain-overlay" />
        <div className="floating-circle" style={{ width: "500px", height: "500px", top: "-100px", right: "-150px" }} />
        <div className="floating-circle" style={{ width: "300px", height: "300px", bottom: "100px", left: "-80px", animationDelay: "3s" }} />
        <div style={{ position: "absolute", top: 0, right: "35%", width: "1px", height: "100%", background: "linear-gradient(to bottom, transparent, rgba(201,168,76,0.25), transparent)" }} />

        <div style={{ maxWidth: "1200px", margin: "0 auto", padding: "80px 40px", width: "100%" }}>
          <div style={{ maxWidth: "680px" }}>
            <div className={`hero-text ${heroVisible ? "visible" : ""}`}>
              <p className="section-label">İstanbul'un En İyi Kahvesi</p>
            </div>
            <h1 className={`hero-text hero-delay-1 hero-title ${heroVisible ? "visible" : ""}`}
              style={{ fontSize: "clamp(52px, 7vw, 96px)", fontWeight: 300, color: "white", lineHeight: 1.05, marginBottom: "28px", letterSpacing: "-1px" }}>
              Her Yudumda<br />
              <span style={{ fontStyle: "italic", color: "var(--gold)" }}>Mükemmellik</span>
            </h1>
            <p className={`hero-text hero-delay-2 ${heroVisible ? "visible" : ""} jost`}
              style={{ color: "rgba(255,255,255,0.6)", fontSize: "17px", lineHeight: 1.8, marginBottom: "48px", fontWeight: 300, maxWidth: "480px" }}>
              Coffee Express olarak her fincanda tutkuyla hazırlanan, özenle seçilmiş çekirdeklerden mükemmel kahve deneyimi sunuyoruz.
            </p>
            <div className={`hero-text hero-delay-3 ${heroVisible ? "visible" : ""}`} style={{ display: "flex", gap: "16px", flexWrap: "wrap" }}>
              <button className="btn-primary" onClick={() => scrollTo("menu")}>Menüyü Keşfet</button>
              <button className="btn-outline" onClick={() => scrollTo("branches")}>Şubeleri Bul</button>
            </div>
          </div>

          <div style={{ marginTop: "100px", display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(120px, 1fr))", gap: "48px", maxWidth: "600px", borderTop: "1px solid rgba(255,255,255,0.08)", paddingTop: "48px" }}>
            {[["4", "Şube"], ["50+", "Kahve Çeşidi"], ["2018", "Kuruluş"], ["10K+", "Mutlu Müşteri"]].map(([num, label]) => (
              <div key={label}>
                <div style={{ fontSize: "clamp(36px, 5vw, 60px)", fontWeight: 300, color: "var(--gold)", lineHeight: 1 }}>{num}</div>
                <div className="jost" style={{ color: "rgba(255,255,255,0.45)", fontSize: "11px", letterSpacing: "2px", textTransform: "uppercase", marginTop: "6px" }}>{label}</div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ position: "absolute", bottom: "40px", left: "50%", transform: "translateX(-50%)", textAlign: "center" }}>
          <div className="jost" style={{ color: "rgba(255,255,255,0.3)", fontSize: "10px", letterSpacing: "3px", textTransform: "uppercase", marginBottom: "12px" }}>Scroll</div>
          <div style={{ width: "1px", height: "40px", background: "linear-gradient(to bottom, rgba(201,168,76,0.6), transparent)", margin: "0 auto" }} />
        </div>
      </section>

      {/* ABOUT */}
      <section id="about" style={{ padding: "120px 40px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          <div className="two-col" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "80px", alignItems: "center" }}>
            <div>
              <p className="section-label">Hakkımızda</p>
              <h2 style={{ fontSize: "clamp(36px, 4vw, 58px)", fontWeight: 300, lineHeight: 1.1, marginBottom: "24px", color: "var(--navy)" }}>
                Kahveye Olan<br /><span style={{ fontStyle: "italic" }}>Tutkumuz</span>
              </h2>
              <div className="divider" style={{ marginBottom: "32px" }} />
              <p className="jost" style={{ color: "#4a5568", lineHeight: 1.9, fontSize: "15px", marginBottom: "20px", fontWeight: 300 }}>
                2018 yılında İstanbul'da kurulan Coffee Express, en kaliteli kahve çekirdeklerini dünyanın dört bir yanından getirerek şehrin kalbinde özgün bir kahve deneyimi yaratmaktadır.
              </p>
              <p className="jost" style={{ color: "#4a5568", lineHeight: 1.9, fontSize: "15px", marginBottom: "40px", fontWeight: 300 }}>
                Uzman baristalarımız her fincanı sanatkârane bir özenle hazırlar. Amacımız; sadece kahve sunmak değil, unutulmaz bir an yaratmaktır.
              </p>
              <button className="btn-primary" style={{ background: "var(--navy)", color: "white" }} onClick={() => scrollTo("contact")}>İletişime Geç</button>
            </div>
            <div style={{ position: "relative" }}>
              <div style={{ background: "linear-gradient(135deg, var(--navy) 0%, var(--navy-mid) 100%)", height: "500px", position: "relative", overflow: "hidden" }}>
                <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", flexDirection: "column", gap: "16px" }}>
                  <div style={{ fontSize: "80px" }}>☕</div>
                  <div className="jost" style={{ color: "rgba(255,255,255,0.25)", fontSize: "12px", letterSpacing: "3px" }}>COFFEE EXPRESS</div>
                </div>
                <div style={{ position: "absolute", top: 0, right: 0, width: "80px", height: "80px", borderTop: "3px solid var(--gold)", borderRight: "3px solid var(--gold)" }} />
                <div style={{ position: "absolute", bottom: 0, left: 0, width: "80px", height: "80px", borderBottom: "3px solid var(--gold)", borderLeft: "3px solid var(--gold)" }} />
              </div>
              <div style={{ position: "absolute", bottom: "-30px", left: "-30px", background: "white", padding: "24px 32px", boxShadow: "0 24px 60px rgba(10,22,40,0.15)", borderLeft: "4px solid var(--gold)" }}>
                <div style={{ fontSize: "28px", fontWeight: 300, color: "var(--navy)" }}>%100</div>
                <div className="jost" style={{ fontSize: "12px", letterSpacing: "2px", color: "#666", textTransform: "uppercase" }}>Etik Kaynak</div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* MENU */}
      <section id="menu" style={{ background: "var(--navy)", padding: "120px 40px", position: "relative", overflow: "hidden" }}>
        <div className="grain-overlay" />
        <div style={{ maxWidth: "1200px", margin: "0 auto", position: "relative" }}>
          <div style={{ textAlign: "center", marginBottom: "64px" }}>
            <p className="section-label">Lezzetlerimiz</p>
            <h2 style={{ fontSize: "clamp(36px, 4vw, 58px)", fontWeight: 300, color: "white", lineHeight: 1.1, marginBottom: "16px" }}>Menümüz</h2>
            <p className="jost" style={{ color: "rgba(255,255,255,0.35)", fontSize: "13px" }}>* KDV hariç fiyatlardır</p>
          </div>

          <div style={{ display: "flex", justifyContent: "center", gap: "12px", marginBottom: "52px", flexWrap: "wrap" }}>
            {MENU_ITEMS.map((cat, i) => (
              <button key={cat.category}
                className={`menu-cat-btn ${menuCat === i ? "active-gold" : ""}`}
                style={{
                  background: menuCat === i ? "var(--gold)" : "transparent",
                  borderColor: menuCat === i ? "var(--gold)" : "rgba(255,255,255,0.2)",
                  color: menuCat === i ? "var(--navy)" : "rgba(255,255,255,0.7)"
                }}
                onClick={() => setMenuCat(i)}>
                {cat.category}
              </button>
            ))}
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "2px" }}>
            {MENU_ITEMS[menuCat].items.map((item) => (
              <div key={item.name} className="card-hover" style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.07)", padding: "32px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "12px" }}>
                  <h3 style={{ fontSize: "20px", fontWeight: 400, color: "white" }}>{item.name}</h3>
                  <span className="jost" style={{ color: "var(--gold)", fontWeight: 500, fontSize: "16px", whiteSpace: "nowrap", marginLeft: "16px" }}>₺{item.price}</span>
                </div>
                <p className="jost" style={{ color: "rgba(255,255,255,0.45)", fontSize: "13px", lineHeight: 1.7, fontWeight: 300 }}>{item.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* BRANCHES */}
      <section id="branches" style={{ padding: "120px 40px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: "64px" }}>
            <p className="section-label">Bizi Bulun</p>
            <h2 style={{ fontSize: "clamp(36px, 4vw, 58px)", fontWeight: 300, color: "var(--navy)", lineHeight: 1.1 }}>Şubelerimiz</h2>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(260px, 1fr))", gap: "24px" }}>
            {BRANCHES.map((branch) => (
              <div key={branch.name} className="branch-card">
                <div style={{ width: "48px", height: "48px", background: "var(--navy)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", marginBottom: "20px", fontSize: "20px" }}>📍</div>
                <h3 style={{ fontSize: "22px", fontWeight: 600, marginBottom: "12px", color: "var(--navy)" }}>{branch.name}</h3>
                <div className="divider" style={{ marginBottom: "20px" }} />
                <p className="jost" style={{ color: "#555", fontSize: "13px", lineHeight: 1.7, marginBottom: "8px" }}>{branch.address}</p>
                <p className="jost" style={{ color: "#555", fontSize: "13px", marginBottom: "4px" }}>📞 {branch.phone}</p>
                <p className="jost" style={{ color: "#555", fontSize: "13px", marginBottom: "24px" }}>🕐 {branch.hours}</p>
                <a href={branch.mapUrl} target="_blank" rel="noopener noreferrer"
                  className="jost"
                  style={{ color: "var(--navy)", fontSize: "11px", letterSpacing: "2px", textTransform: "uppercase", fontWeight: 600, textDecoration: "none", borderBottom: "1px solid var(--gold)", paddingBottom: "2px" }}>
                  Haritada Gör →
                </a>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CONTACT */}
      <section id="contact" style={{ background: "var(--navy-light)", padding: "120px 40px", position: "relative", overflow: "hidden" }}>
        <div className="grain-overlay" />
        <div style={{ maxWidth: "1200px", margin: "0 auto", position: "relative" }}>
          <div className="two-col" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "80px", alignItems: "center" }}>
            <div>
              <p className="section-label">Bize Ulaşın</p>
              <h2 style={{ fontSize: "clamp(36px, 4vw, 58px)", fontWeight: 300, color: "white", lineHeight: 1.1, marginBottom: "24px" }}>
                İletişime <span style={{ fontStyle: "italic", color: "var(--gold)" }}>Geçin</span>
              </h2>
              <div className="divider" style={{ marginBottom: "32px" }} />
              <p className="jost" style={{ color: "rgba(255,255,255,0.55)", lineHeight: 1.9, fontSize: "15px", marginBottom: "40px", fontWeight: 300 }}>
                Sorularınız, önerileriniz ya da kurumsal talepleriniz için bizimle iletişime geçin. En kısa sürede size dönüş yapacağız.
              </p>
              <div style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
                {[["📧", "info@coffeeexpress.com.tr"], ["📞", "+90 850 000 00 00"], ["📱", "WhatsApp ile Yaz"]].map(([icon, text]) => (
                  <div key={text} className="jost" style={{ display: "flex", alignItems: "center", gap: "16px", color: "rgba(255,255,255,0.65)", fontSize: "14px" }}>
                    <span style={{ fontSize: "20px" }}>{icon}</span>{text}
                  </div>
                ))}
              </div>
            </div>
            <div>
              <div style={{ display: "flex", flexDirection: "column", gap: "32px" }}>
                <input className="input-field" placeholder="Adınız" type="text" />
                <input className="input-field" placeholder="E-posta Adresiniz" type="email" />
                <input className="input-field" placeholder="Konunuz" type="text" />
                <textarea className="input-field" placeholder="Mesajınız" rows={4} style={{ resize: "none" }} />
                <button className="btn-primary">Mesaj Gönder</button>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* FOOTER */}
      <footer style={{ background: "var(--navy)", borderTop: "1px solid rgba(255,255,255,0.06)", padding: "40px" }}>
        <div style={{ maxWidth: "1200px", margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: "24px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
            <div style={{ width: "30px", height: "30px", background: "var(--gold)", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "14px" }}>☕</div>
            <div>
              <div style={{ color: "white", fontWeight: 700, fontSize: "15px", letterSpacing: "1px" }}>COFFEE</div>
              <div className="jost" style={{ color: "var(--gold)", fontSize: "9px", letterSpacing: "4px" }}>EXPRESS</div>
            </div>
          </div>
          <div style={{ display: "flex", gap: "24px" }}>
            {["Instagram", "Facebook", "Twitter", "LinkedIn"].map((sm) => (
              <a key={sm} href="#" className="social-link">{sm}</a>
            ))}
          </div>
          <p className="jost" style={{ color: "rgba(255,255,255,0.25)", fontSize: "12px" }}>© 2025 Coffee Express. Tüm hakları saklıdır.</p>
        </div>
      </footer>

      {/* WhatsApp Float */}
      <a href={`https://wa.me/${WHATSAPP_NUMBER}`} target="_blank" rel="noopener noreferrer" className="wa-btn" title="WhatsApp ile Yaz">
        <svg width="28" height="28" viewBox="0 0 24 24" fill="white">
          <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/>
        </svg>
      </a>
    </div>
  );
}
